def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    avg_capacity = np.mean(bins[bins > 0]) if np.any(bins > 0) else 1
    median_capacity = np.median(bins[bins > 0]) if np.any(bins > 0) else 1
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity * 1.05:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 1:
            score = (ratio - 1) ** 3 * 10 + 5
        elif ratio == 1:
            score = 0
        elif 0.85 < ratio < 1:
            score = np.cos(ratio * np.pi) + 1.2
        elif 0.6 < ratio <= 0.85:
            score = np.log(1.1 - ratio) * -1.5 + 0.3
        elif 0.3 < ratio <= 0.6:
            for k in range(1, 10):
                term = ((-1) ** (k+1)) * (ratio ** (k + 1)) / (k ** 1.2)
                score += term
            score = abs(score) + 0.05
        else:
            score = 0.2 + (0.3 / (ratio + 0.1))
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 8):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.2)
                    neighbors_influence += diff_ratio * weight * 0.08
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        capacity_factor = (capacity ** 0.5) * (avg_capacity ** 0.3) * (median_capacity ** 0.2)
        if capacity_factor == 0:
            capacity_factor = 1
        penalty = 0
        if capacity < item:
            penalty = (item - capacity) ** 2 * 0.7
        if i % 4 == 0:
            score *= 0.9
            neighbors_influence *= 1.15
        elif i % 6 == 0:
            score *= 1.1
            neighbors_influence *= 0.9
        priority = score + neighbors_influence / capacity_factor + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 6.2
    smoothed_priorities = priorities.copy()
    for i in range(1, n-1):
        neighbors_avg = (priorities[i-1] + priorities[i+1]) / 2
        diff = abs(priorities[i] - neighbors_avg)
        if diff > max(1.0, 0.2 * neighbors_avg):
            smoothed_priorities[i] = 0.7 * priorities[i] + 0.3 * neighbors_avg
    return smoothed_priorities
